  direction = 1;
  patrolMin = 100;
  patrolMax = 500;

  update(sprite: Phaser.Physics.Arcade.Sprite) {
    sprite.setVelocityX(100 * this.direction);
    if (sprite.x >= this.patrolMax) this.direction = -1;
    if (sprite.x <= this.patrolMin) this.direction = 1;
    sprite.setFlipX(this.direction < 0);
  }
}

